    public void startReloadingBoosters() {
        this.boostersController = new BoostersController(this);
        this.boostersController.refresh();
        if (this.getConfig("settings").bool("storage-options.bungee-fix")) {
            long l = (long)this.getConfig("settings").integer("storage-options.auto-save-interval") * 20L;
            FoliaScheduler.runTaskTimer((Plugin)this, this::refreshBoosters, l, l);
        }
    }

    public void refreshBoosters() {
        this.boosterCache.invalidateAll();
        this.boosterCache.loadAsyncAll().thenRun(this.boostersController::refresh);
    }

    private void setSeasonDate() {
        Config config = this.getConfig("settings");
        String[] stringArray = config.string("current-season.start-date").split("/");
        String[] stringArray2 = config.string("current-season.start-time").split(":");
        int n = Integer.parseInt(stringArray[2]);
        int n2 = Integer.parseInt(stringArray[1]);
        int n3 = Integer.parseInt(stringArray[0]);
        int n4 = Integer.parseInt(stringArray2[0]);
        int n5 = Integer.parseInt(stringArray2[1]);
        String string = config.string("current-season.time-zone");
        this.seasonStartDate = ZonedDateTime.of(n, n2, n3, n4, n5, 0, 0, ZoneId.of(string));
        this.seasonEndDate = this.seasonStartDate.plusWeeks(this.questCache.getMaxWeek());
    }

