    private void placeholderHook() {
        if (this.getServer().getPluginManager().isPluginEnabled("PlaceholderAPI")) {
            this.placeholderApiHook = new PlaceholderApiHook(this);
            this.placeholderApiHook.register();
            return;
        }
        if (this.placeholderApiHook == null && this.placeholderRuns < 10) {
            ++this.placeholderRuns;
            FoliaScheduler.runTaskLater((Plugin)this, this::placeholderHook, 100L);
        }
    }

    private void vaultHook() {
        if (!this.getConfig("settings").has("reward-excess-points.method") || this.getConfig("settings").string("reward-excess-points.method").equalsIgnoreCase("none")) {
            return;
        }
        if (this.getServer().getPluginManager().isPluginEnabled("Vault")) {
            RegisteredServiceProvider registeredServiceProvider = this.getServer().getServicesManager().getRegistration(Economy.class);
            if (registeredServiceProvider != null) {
                this.economy = (Economy)registeredServiceProvider.getProvider();
                this.getServer().getLogger().info("[BattlePass] Hooked into vault");
                return;
            }
            return;
        }
        if (this.economy == null && this.economyRuns < 10) {
            ++this.economyRuns;
            FoliaScheduler.runTaskLater((Plugin)this, this::vaultHook, 100L);
        }
    }

