    private boolean checkIfAffects(BoosterEntity boosterEntity, IBoostable iBoostable) {
        IBoostable iBoostable2;
        if (boosterEntity.getExpires() < System.currentTimeMillis()) {
            return false;
        }
        String string = boosterEntity.getAffects().replaceAll(" ", "");
        if (string.isEmpty() || string.equalsIgnoreCase("all")) {
            return true;
        }
        List<String> list = Arrays.asList(string.split(","));
        if (iBoostable instanceof Quest) {
            iBoostable2 = (Quest)iBoostable;
            if (((Quest)iBoostable2).getCategoryId().startsWith("week") && list.contains("week")) {
                return true;
            }
            if (list.contains(((Quest)iBoostable2).getCategoryId())) {
                return true;
            }
            if (list.contains(((Quest)iBoostable2).getCategoryId() + "-" + ((Quest)iBoostable2).getId())) {
                return true;
            }
        }
        if (iBoostable instanceof TierReward) {
            iBoostable2 = (TierReward)iBoostable;
            if (list.contains("tier-" + ((TierReward)iBoostable2).getTier())) {
                return true;
            }
            return list.contains("reward-" + ((TierReward)iBoostable2).getReward().getId());
        }
        return false;
    }

