public class ChestShopQuests
extends ActionQuestExecutor {
    public ChestShopQuests(JavaPlugin javaPlugin) {
        super(javaPlugin, "chestshop");
    }

    @EventHandler(ignoreCancelled=true)
    public void afterShopCreate(ShopCreatedEvent shopCreatedEvent) {
        Player player = shopCreatedEvent.getPlayer();
        this.execute("create", player, ActionResult::none);
    }

    @EventHandler(ignoreCancelled=true)
    public void onTransaction(TransactionEvent transactionEvent) {
        Player player = transactionEvent.getClient();
        double d = transactionEvent.getExactPrice().doubleValue();
        ItemStack itemStack2 = Arrays.stream(transactionEvent.getStock()).filter(itemStack -> itemStack != null && itemStack.getType() != Material.AIR).findFirst().orElse(new ItemStack(Material.AIR));
        String string = transactionEvent.getOwnerAccount().getName();
        Player player2 = Bukkit.getPlayer((UUID)transactionEvent.getOwnerAccount().getUuid());
        int n = itemStack2.getAmount();
        if (player == null) {
            return;
        }
        if (transactionEvent.getTransactionType() == TransactionEvent.TransactionType.BUY) {
            this.execute("buy", player, n, actionResult -> actionResult.root(string).subRoot(itemStack2));
            this.execute("spend", player, (int)Math.round(d), actionResult -> actionResult.root(string));
            if (player2 != null) {
                this.execute("sell", player2, n, actionResult -> actionResult.root(player.getName()).subRoot(itemStack2));
                this.execute("profit", player2, (int)Math.round(d), actionResult -> actionResult.root(player.getName()));
            }
        } else {
            this.execute("sell", player, n, actionResult -> actionResult.root(string).subRoot(itemStack2));
            this.execute("profit", player, (int)Math.round(d), actionResult -> actionResult.root(string));
            if (player2 != null) {
                this.execute("buy", player2, n, actionResult -> actionResult.root(player.getName()).subRoot(itemStack2));
                this.execute("spend", player2, (int)Math.round(d), actionResult -> actionResult.root(player.getName()));
            }
        }
    }

    @EventHandler(ignoreCancelled=true)
    public void afterShopCreate(ShopDestroyedEvent shopDestroyedEvent) {
        Player player = shopDestroyedEvent.getDestroyer();
        this.execute("destroy", player, ActionResult::none);
    }
}

