    public static BlockFace getCardinalDirection(float f) {
        if (f < 0.0f) {
            f += 360.0f;
        }
        if ((f %= 360.0f) <= 45.0f) {
            return BlockFace.NORTH;
        }
        if (f <= 135.0f) {
            return BlockFace.EAST;
        }
        if (f <= 225.0f) {
            return BlockFace.SOUTH;
        }
        if (f <= 315.0f) {
            return BlockFace.WEST;
        }
        return BlockFace.NORTH;
    }

